macros.token:
#if $image.ext in ("tiff", "tif")
    {
        pages=\$(tr -d '[] ' < '$image.metadata.offsets' | tr ',' '\n' | grep -c '[0-9]');

        if [ "\$pages" -gt 1 ]; then
            echo "Multi-page TIF(F) input is not supported by kraken 7. Detected \$pages pages. Please use PDF input or split it first." >&2;
            exit 1;
        fi;
    } &&
#end if
